create extension if not exists pgcrypto;
alter table public.cms_programmes add column if not exists department text not null default 'Agricultural Training', add column if not exists duration text not null default 'To be confirmed', add column if not exists delivery_mode text not null default 'Contact learning', add column if not exists location text not null default 'To be confirmed', add column if not exists image_url text, add column if not exists price_cents integer not null default 0, add column if not exists registration_fee_cents integer not null default 0, add column if not exists is_available boolean not null default false, add column if not exists available_intake text;
alter table public.cms_programmes add constraint cms_programmes_payment_amounts_check check (price_cents >= 0 and registration_fee_cents >= 0);
create table public.enrollments (id uuid primary key default gen_random_uuid(), course_id bigint not null references public.cms_programmes(id) on delete restrict, first_name text not null, last_name text not null, email text not null, phone text not null, id_passport_number text not null, date_of_birth date, address text not null, qualification text not null, preferred_intake text not null, notes text, status text not null default 'pending_payment' check (status in ('pending_payment','submitted','under_review','accepted','rejected','cancelled')), payment_status text not null default 'pending' check (payment_status in ('pending','paid','failed','refunded')), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.payments (id uuid primary key default gen_random_uuid(), enrollment_id uuid not null references public.enrollments(id) on delete restrict, course_id bigint not null references public.cms_programmes(id) on delete restrict, paystack_reference text not null unique, amount integer not null check (amount > 0), currency text not null default 'ZAR' check (currency = 'ZAR'), status text not null default 'pending' check (status in ('pending','initialization_failed','success','failed','refunded')), paid_at timestamptz, paystack_transaction_id text, customer_email text not null, raw_response jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index enrollments_course_id_idx on public.enrollments(course_id); create index enrollments_email_idx on public.enrollments(email); create index payments_enrollment_id_idx on public.payments(enrollment_id); create index payments_course_id_idx on public.payments(course_id); create index payments_status_idx on public.payments(status);
alter table public.enrollments enable row level security; alter table public.enrollments force row level security; alter table public.payments enable row level security; alter table public.payments force row level security;
revoke all on public.enrollments from public, anon, authenticated; revoke all on public.payments from public, anon, authenticated;
grant select, insert, update on public.enrollments to service_role; grant select, insert, update on public.payments to service_role;
comment on table public.enrollments is 'Private course enrolments created only through the secure server API.'; comment on table public.payments is 'Paystack transactions; no card information is stored.';
